import Link from 'next/link';
import { PageHeader, SurfaceCard } from '../../components/ui';
import { activeMockUser, canView, getVisibleStudents } from '../../mocks';
import styles from './page.module.scss';

export default function StudentsPage() {
  const allowedRoles = activeMockUser.role === 'teacher' || activeMockUser.role === 'admin' || activeMockUser.role === 'super-admin';
  if (!allowedRoles || !canView('dashboard', activeMockUser.role)) return null;

  const students = getVisibleStudents(activeMockUser.role, activeMockUser.id);

  return (
    <div className={`${styles.page} container container--page`}>
      <PageHeader
        className={styles.pageHeader}
        titleClassName={styles.pageTitle}
        subtitleClassName={styles.pageSub}
        title="Students"
        subtitle={
          activeMockUser.role === 'teacher'
            ? 'Only students assigned to you'
            : 'All students and their assigned teachers'
        }
      />

      <div className={styles.grid}>
        {students.map((student) => (
          <SurfaceCard key={student.id} className={styles.card}>
            <div className={styles.cardTop}>
              <div className={styles.avatar}>
                {student.fullName
                  .split(' ')
                  .map((part) => part[0])
                  .join('')
                  .slice(0, 2)}
              </div>
              <div className={styles.topMeta}>
                <div className={styles.name}>{student.fullName}</div>
                <div className={styles.teacher}>Teacher: {student.teacherName}</div>
              </div>
            </div>

            <div className={styles.metaRow}>
              <span className={styles.badge}>{student.level}</span>
              <span className={`${styles.badge} ${student.status === 'active' ? styles.badgeGreen : styles.badgeAmber}`}>
                {student.status}
              </span>
            </div>

            <div className={styles.meta}>Email: {student.email}</div>

            <div className={styles.cardFooter}>
              <Link href={`/students/${student.id}`} className={styles.openLink}>
                Open profile
              </Link>
            </div>
          </SurfaceCard>
        ))}
      </div>
    </div>
  );
}
